import { createLinkAction, retryLinkEnrichmentAction } from "@/app/app/links/actions";
import {
  Button,
  DetailBlock,
  FormField,
  IntroBlock,
  MetadataRow,
  SectionHeading,
  Surface,
  TagChip,
  TagList
} from "@/components/ui/primitives";
import { EnrichmentPendingRefresh } from "@/features/enrichment/components/pending-refresh";
import { EnrichmentStatusBlock } from "@/features/enrichment/components/status-block";
import { listOwnerLinks } from "@/features/links/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

type LinksPageProps = {
  searchParams?: Promise<{
    saved?: string;
    retried?: string;
    error?: string;
  }>;
};

function getStatusMessage(error?: string) {
  switch (error) {
    case "duplicate-url":
      return "That URL is already saved in your private links.";
    case "invalid-url":
      return "Enter a complete http:// or https:// URL.";
    case "missing-title":
      return "Enter a title for the saved link.";
    default:
      return undefined;
  }
}

export default async function LinksPage({ searchParams }: LinksPageProps) {
  const owner = await requireOwnerSession();
  const resolvedSearchParams = (await searchParams) ?? {};
  const links = await listOwnerLinks(owner.id);
  const pendingLinks = links.filter((link) => link.enrichment.status === "pending").length;
  const dateFormatter = new Intl.DateTimeFormat("en", { dateStyle: "medium" });
  const statusMessage =
    resolvedSearchParams.saved === "1"
      ? "Link saved."
      : resolvedSearchParams.retried === "1"
        ? "Retry requested."
        : getStatusMessage(resolvedSearchParams.error);

  return (
    <div className="feature-layout">
      <EnrichmentPendingRefresh enabled={links.some((link) => link.enrichment.status === "pending")} />
      <Surface className="secondary-route-hero" density="compact" tone="hero">
        <IntroBlock
          compact
          description="Manual bookmark capture stays private in v1. Save the URL and title first, then let Minakeep generate the AI summary and shared tags after save."
          eyebrow="Private links"
          title="Reference shelf"
        >
          <div aria-label="Links overview" className="ui-support-grid secondary-summary-grid">
            <DetailBlock title="Saved links">
              <p>{links.length} private reference{links.length === 1 ? "" : "s"}</p>
            </DetailBlock>
            <DetailBlock title="AI queue">
              <p>{pendingLinks === 0 ? "No pending enrichment" : `${pendingLinks} link${pendingLinks === 1 ? "" : "s"} pending`}</p>
            </DetailBlock>
            <DetailBlock title="Visibility">
              <p>Links remain private even when notes can be published.</p>
            </DetailBlock>
          </div>
        </IntroBlock>
        {statusMessage ? (
          <p className={resolvedSearchParams.error ? "status-note status-note-error" : "status-note"}>{statusMessage}</p>
        ) : null}
      </Surface>

      <div className="link-manager-grid secondary-route-grid">
        <Surface action={createLinkAction} as="form" className="link-form secondary-control-panel" density="compact" tone="panel">
          <SectionHeading meta="Manual URL and title" title="Capture" />
          <FormField label="URL">
            <input
              autoComplete="url"
              className="text-input"
              name="url"
              placeholder="https://example.com/article"
              required
              type="url"
            />
          </FormField>
          <FormField label="Title">
            <input
              autoComplete="off"
              className="text-input"
              name="title"
              placeholder="Reference title"
              required
              type="text"
            />
          </FormField>
          <p className="field-note">AI summary and shared tags are generated automatically after save.</p>
          <div className="button-row">
            <Button type="submit">Save link</Button>
          </div>
        </Surface>

        <Surface className="link-list-panel secondary-list-panel secondary-link-panel" density="compact" tone="panel">
          <SectionHeading meta={`${links.length} saved`} title="Saved links" />
          {links.length === 0 ? (
            <p>No saved links yet. Capture the first private bookmark from this page.</p>
          ) : (
            <div className="link-list">
              {links.map((link) => (
                <article className="link-list-item secondary-link-item" key={link.id}>
                  <div className="secondary-link-main">
                    <div className="link-list-heading secondary-link-heading">
                      <MetadataRow leading>
                        <span>Private link</span>
                        <span>{dateFormatter.format(link.updatedAt)}</span>
                      </MetadataRow>
                      <a className="note-list-link" href={link.url} rel="noopener noreferrer" target="_blank">
                        {link.title}
                      </a>
                      <p className="link-url">{link.url}</p>
                    </div>
                    <div className="link-list-footer secondary-link-footer">
                      <MetadataRow>
                        <span>Visibility</span>
                        <span>Owner only</span>
                      </MetadataRow>
                    </div>
                  </div>
                  <div className="secondary-link-meta">
                    <EnrichmentStatusBlock detailClassName="secondary-link-status" state={link.enrichment} />
                    <div className="note-generated-copy secondary-generated-copy">
                      <strong>AI summary:</strong>
                      {link.summary ? (
                        <p className="link-summary" data-testid="link-ai-summary">
                          {link.summary}
                        </p>
                      ) : (
                        <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
                      )}
                    </div>
                    <div className="note-generated-copy secondary-generated-copy">
                      <strong>AI tags</strong>
                      <TagList aria-label="Link tags" data-testid="link-ai-tags">
                        {link.tags.length === 0 ? (
                          <TagChip muted>No generated tags yet</TagChip>
                        ) : (
                          link.tags.map((tag) => (
                            <TagChip key={tag.id}>
                              {tag.name}
                            </TagChip>
                          ))
                        )}
                      </TagList>
                    </div>
                  </div>
                  {link.enrichment.status === "failed" ? (
                    <form action={retryLinkEnrichmentAction.bind(null, link.id)} className="secondary-link-retry">
                      <Button type="submit" variant="ghost">
                        Retry AI enrichment
                      </Button>
                    </form>
                  ) : null}
                </article>
              ))}
            </div>
          )}
        </Surface>
      </div>
    </div>
  );
}

import type { EnrichmentState } from "@/features/enrichment/types";
import type { SavedTag } from "@/features/tags/types";

export type LinkDraftInput = {
  url: string;
  title: string;
};

export type SavedLinkSummary = {
  id: string;
  url: string;
  title: string;
  summary: string | null;
  isPublished: boolean;
  publishedAt: Date | null;
  enrichment: EnrichmentState;
  tags: SavedTag[];
  createdAt: Date;
  updatedAt: Date;
};

export type PublishedLinkSummary = {
  id: string;
  url: string;
  title: string;
  summary: string | null;
  publishedAt: Date;
  updatedAt: Date;
  tags: SavedTag[];
};

import "server-only";

import { Prisma } from "@prisma/client";

import { requestEnrichment, retryEnrichment } from "@/features/enrichment/service";
import { normalizeLinkInput } from "@/features/links/normalize";
import { linksRepo } from "@/features/links/repo";
import type { LinkDraftInput } from "@/features/links/types";

export class DuplicateLinkUrlError extends Error {
  constructor() {
    super("duplicate-link-url");
    this.name = "DuplicateLinkUrlError";
  }
}

export async function listOwnerLinks(ownerId: string) {
  return linksRepo.listForOwner(ownerId);
}

export async function listPublishedLinks() {
  const links = await linksRepo.listPublished();

  return links.filter((link): link is typeof link & { publishedAt: Date } => link.publishedAt !== null);
}

export async function createSavedLink(ownerId: string, input: LinkDraftInput) {
  const normalizedInput = normalizeLinkInput(input);

  try {
    return await linksRepo.create(ownerId, normalizedInput);
  } catch (error) {
    if (error instanceof Prisma.PrismaClientKnownRequestError && error.code === "P2002") {
      throw new DuplicateLinkUrlError();
    }

    throw error;
  }
}

export async function publishLink(ownerId: string, id: string) {
  const existingLink = await linksRepo.findByIdForOwner(ownerId, id);

  if (!existingLink) {
    return null;
  }

  if (existingLink.isPublished) {
    return existingLink;
  }

  return linksRepo.updatePublication(id, true);
}

export async function unpublishLink(ownerId: string, id: string) {
  const existingLink = await linksRepo.findByIdForOwner(ownerId, id);

  if (!existingLink) {
    return null;
  }

  if (!existingLink.isPublished) {
    return existingLink;
  }

  return linksRepo.updatePublication(id, false);
}

export async function retryLinkEnrichment(ownerId: string, id: string) {
  const link = await linksRepo.findByIdForOwner(ownerId, id);

  if (!link) {
    return null;
  }

  return retryEnrichment(linksRepo, id, link);
}

export async function startLinkEnrichment(id: string) {
  return requestEnrichment(linksRepo, id);
}

import type { PublishedLinkSummary } from "@/features/links/types";
import type { PublishedNoteSummary } from "@/features/notes/types";
import type { SavedTag } from "@/features/tags/types";

export type PublicContentKind = "note" | "link";

type PublishedPublicContentBase = {
  id: string;
  kind: PublicContentKind;
  title: string;
  summary: string | null;
  publishedAt: Date;
  updatedAt: Date;
  tags: SavedTag[];
};

export type PublishedPublicNote = PublishedPublicContentBase & {
  kind: "note";
  excerpt: string;
  slug: string;
};

export type PublishedPublicLink = PublishedPublicContentBase & {
  kind: "link";
  url: string;
};

export type PublishedPublicContent = PublishedPublicNote | PublishedPublicLink;

export function toPublishedPublicNote(note: PublishedNoteSummary): PublishedPublicNote {
  return {
    id: note.id,
    kind: "note",
    title: note.title,
    summary: note.summary,
    publishedAt: note.publishedAt,
    updatedAt: note.updatedAt,
    tags: note.tags,
    excerpt: note.excerpt,
    slug: note.slug
  };
}

export function toPublishedPublicLink(link: PublishedLinkSummary): PublishedPublicLink {
  return {
    id: link.id,
    kind: "link",
    title: link.title,
    summary: link.summary,
    publishedAt: link.publishedAt,
    updatedAt: link.updatedAt,
    tags: link.tags,
    url: link.url
  };
}

export function comparePublishedContent(a: PublishedPublicContent, b: PublishedPublicContent) {
  const publishedAtDiff = b.publishedAt.getTime() - a.publishedAt.getTime();

  if (publishedAtDiff !== 0) {
    return publishedAtDiff;
  }

  const updatedAtDiff = b.updatedAt.getTime() - a.updatedAt.getTime();

  if (updatedAtDiff !== 0) {
    return updatedAtDiff;
  }

  return a.title.localeCompare(b.title);
}

export function sortPublishedContent(items: PublishedPublicContent[]) {
  return [...items].sort(comparePublishedContent);
}

import "server-only";

import { listPublishedLinks } from "@/features/links/service";
import { listPublishedNotes } from "@/features/notes/service";
import { sortPublishedContent, toPublishedPublicLink, toPublishedPublicNote } from "@/features/public-content/types";

export async function listPublishedContent() {
  const [notes, links] = await Promise.all([listPublishedNotes(), listPublishedLinks()]);

  return sortPublishedContent([...notes.map(toPublishedPublicNote), ...links.map(toPublishedPublicLink)]);
}

import "dotenv/config";

import { expect, test } from "@playwright/test";

import { setAiPlaywrightTestMode } from "./ai-test-mode";

// These journeys all mutate the same single-owner SQLite state, so serial execution keeps promotion checks deterministic.
test.describe.configure({ mode: "serial" });

test("public homepage exposes the published notes surface", async ({ page }) => {
  await page.goto("/");

  const emptyState = page.getByText("No published notes yet.");
  const publishedNoteEntry = page.locator(".note-preview-card").first();

  await expect(page.getByRole("heading", { name: "Notes the owner has chosen to share." })).toBeVisible();
  await expect(page.getByRole("navigation").getByRole("link", { name: "Owner login" })).toBeVisible();
  await expect(emptyState.or(publishedNoteEntry)).toBeVisible();
});

test("anonymous visitors cannot access the owner search route", async ({ page }) => {
  await page.goto("/app/search");

  await expect(page).toHaveURL(/\/login/);
});

test("owner can sign in, create a draft note, edit it, and reopen it with rendered preview", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const initialTitle = `Draft note ${uniqueId}`;
  const updatedTitle = `Updated draft note ${uniqueId}`;
  const initialMarkdown = `# Preview ${uniqueId}

- first item
- second item`;
  const updatedMarkdown = `## Revised ${uniqueId}

Paragraph with **bold** text and a [link](https://example.com).`;

  await page.goto("/app/notes/new");
  await expect(page).toHaveURL(/\/login/);

  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "New note" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/new$/);
  await page.getByRole("textbox", { name: /^Title$/ }).fill(initialTitle);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(initialMarkdown);

  const initialPreview = page.getByTestId("note-markdown-preview");
  await expect(initialPreview.getByRole("heading", { name: `Preview ${uniqueId}` })).toBeVisible();
  await expect(initialPreview.getByText("first item")).toBeVisible();

  await page.getByRole("button", { name: "Create draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByText("Draft saved.")).toBeVisible();

  await page.getByRole("textbox", { name: /^Title$/ }).fill(updatedTitle);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(updatedMarkdown);

  const updatedPreview = page.getByTestId("note-markdown-preview");
  await expect(updatedPreview.getByRole("heading", { name: `Revised ${uniqueId}` })).toBeVisible();
  await expect(updatedPreview.getByText("bold")).toBeVisible();

  await page.getByRole("button", { name: "Save draft" }).click();

  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
  await expect(page.getByTestId("note-enrichment-panel")).toContainText("AI note metadata");
  await page.goto("/app");
  await expect(page.getByRole("link", { name: updatedTitle })).toBeVisible();

  await page.getByRole("link", { name: updatedTitle }).click();
  await expect(page).toHaveURL(/\/app\/notes\/.+\/edit/);
  await expect(page.getByRole("textbox", { name: /^Title$/ })).toHaveValue(updatedTitle);
  await expect(page.getByRole("textbox", { name: /^Markdown body$/ })).toHaveValue(updatedMarkdown);
  await expect(page.getByTestId("note-markdown-preview").getByRole("heading", { name: `Revised ${uniqueId}` })).toBeVisible();
});

test("note save still succeeds when the configured AI endpoint times out and exposes a retry path", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;

  await setAiPlaywrightTestMode("timeout");

  try {
    await page.goto("/login");
    await page.getByLabel("Username").fill(username);
    await page.getByLabel("Password").fill(password);
    await page.getByRole("button", { name: "Sign in" }).click();

    await expect(page).toHaveURL(/\/app$/);
    await page.getByRole("link", { name: "New note" }).click();

    await page.getByRole("textbox", { name: /^Title$/ }).fill(`Retry note ${uniqueId}`);
    await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(`Body for retry note ${uniqueId}`);
    await page.getByRole("button", { name: "Create draft" }).click();

    await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?saved=1$/);
    const enrichmentPanel = page.getByTestId("note-enrichment-panel");
    await expect(enrichmentPanel).toContainText("AI pending");
    await expect(enrichmentPanel).toContainText("AI failed", { timeout: 15000 });
    await expect(enrichmentPanel).toContainText("The Mina AI endpoint timed out.");
    await expect(page.getByTestId("note-ai-summary")).toHaveCount(0);
    await expect(page.getByRole("button", { name: "Retry AI enrichment" })).toBeVisible();

    await page.getByRole("button", { name: "Retry AI enrichment" }).click();

    await expect(page).toHaveURL(/\/app\/notes\/.+\/edit\?retried=1$/);
    await expect(page.getByText("Retry requested.")).toBeVisible();
    await expect(page.getByTestId("note-enrichment-panel")).toContainText("AI failed", { timeout: 15000 });
    await expect(page.getByTestId("note-enrichment-panel")).toContainText("The Mina AI endpoint timed out.");
  } finally {
    await setAiPlaywrightTestMode("passthrough");
  }
});

test("owner can publish and unpublish a note across the public routes", async ({ page }) => {
  const username = process.env.OWNER_USERNAME ?? "owner";
  const password = process.env.OWNER_PASSWORD ?? "password";
  const uniqueId = `${Date.now()}`;
  const title = `Public note ${uniqueId}`;
  const markdown = `## Shared heading ${uniqueId}

This note should appear on the public site when published.`;
  const slug = `public-note-${uniqueId}`;

  await page.goto("/login");
  await page.getByLabel("Username").fill(username);
  await page.getByLabel("Password").fill(password);
  await page.getByRole("button", { name: "Sign in" }).click();

  await expect(page).toHaveURL(/\/app$/);
  await page.getByRole("link", { name: "New note" }).click();
  await expect(page).toHaveURL(/\/app\/notes\/new$/);

  await page.getByRole("textbox", { name: /^Title$/ }).fill(title);
  await page.getByRole("textbox", { name: /^Markdown body$/ }).fill(markdown);
  await page.getByRole("button", { name: "Create draft" }).click();

